<!-- components/SearchZone.vue -->
<template>
  <div class="search-zone">
    <!-- Logo -->
    <router-link to="/" class="logo">
      <img src="@/assets/logo.png" alt="商城Logo" style="height: 40px">
    </router-link>

    <!-- 搜索框 -->
    <div class="search-box">
      <el-input
          placeholder="搜索商品"
          v-model="searchKeywords"
          @keyup.enter="handleSearch"
      >
        <template #append>
          <el-button
              type="primary"
              icon="search"
              @click="handleSearch"
          />
        </template>
      </el-input>
    </div>
  </div>
</template>

<script setup>
import {onMounted, ref, watch} from 'vue'
import { useRoute,useRouter } from 'vue-router'

const route = useRoute()
const router = useRouter()
const searchKeywords = ref('')
// 新增：初始化时读取路由参数
onMounted(() => {
  if (route.query.search) {
    searchKeywords.value = route.query.search
  }
})

// 监听路由参数变化
watch(
    () => route.query.search,
    (newVal) => {
      searchKeywords.value = newVal || ''
    }
)
const handleSearch = () => {
  if (searchKeywords.value.trim()) {
    router.push({
      path: '/goods',
      query: {
        ...route.query, // 保留原有参数
        search: searchKeywords.value.trim()
      }
    })
  }
}
</script>

<style scoped>
.search-zone {
  display: flex;
  align-items: center;
  gap: 40px;
  flex: 1;
  max-width: 800px;
}

.logo {
  flex-shrink: 0;
}

.search-box {
  flex: 1;
  min-width: 300px;
}

@media (max-width: 768px) {
  .search-zone {
    gap: 20px;
  }

  .logo img {
    height: 30px !important;
  }

  .search-box {
    min-width: 200px;
  }
}
</style>