<template>
  <el-container class="main-container">
    <!-- 顶部导航栏 -->
    <el-header class="main-header">
      <div class="header-content">
        <!-- Logo -->
        <router-link to="/" class="logo">
          <img src="@/assets/logo.png" alt="商城Logo" style="height: 40px">
        </router-link>

        <!-- 搜索框 -->

        <div class="search-box">
          <el-input
              placeholder="搜索商品"
              v-model="searchKeyword"
              class="search-input"
          >
            <template #append>
              <el-button type="primary" icon="search"  @click="handleSearch"/>
            </template>
          </el-input>
        </div>

        <!-- 用户操作区 -->
        <div class="user-actions">
          <template v-if="!isLoggedIn">
            <el-link type="info" :underline="false" href="/login">
              登录
            </el-link>
            <el-link type="info" :underline="false" href="/registry">
              注册
            </el-link>
          </template>
          <template v-else>
            <el-popover
                placement="bottom"
                :width="200"
                trigger="hover"
            >
              <template #reference>
                <el-avatar :size="32" :src="userInfo?.avatar">
                  <el-icon><User /></el-icon>
                </el-avatar>
              </template>
              <div class="user-panel">
                <p>欢迎回来，{{ userInfo?.username || '用户' }}</p>
                <el-button type="danger" size="small" @click="handleLogout">退出登录</el-button>
              </div>
            </el-popover>
          </template>
          <div class="action-buttons">
            <el-button
                type="text"
                icon="Document"
                class="action-btn"
                @click="$router.push('/order')"
            >
              订单
            </el-button>
            <el-button
                type="text"
                icon="ShoppingCart"
                class="action-btn"
                @click="$router.push('/shopCar')"
            >
              购物车
            </el-button>
          </div>
        </div>
      </div>
    </el-header>

    <!-- 主内容区 -->
    <el-main>
      <!-- 轮播图 -->
      <el-carousel :interval="5000" height="400px">
        <el-carousel-item v-for="item in 4" :key="item">
          <img
              :src="require('@/assets/'+item+'.jpg')"
              class="carousel-image"
              alt="促销活动"
          >
        </el-carousel-item>
      </el-carousel>

      <!-- 商品分类 -->
      <div class="category-section">
        <el-row :gutter="20">
          <el-col
              v-for="(category, index) in categories"
              :key="index"
              :xs="12" :sm="8" :md="6" :lg="4"
          >
            <el-card shadow="hover" class="category-card" @click="handleToGoods(category.id)">
              <el-icon :size="40" :color="category.color">
                <component :is="category.icon" />
              </el-icon>
              <h3>{{ category.name }}</h3>
            </el-card>
          </el-col>
        </el-row>
      </div>

      <!-- 商品推荐 -->
      <div class="product-section">
        <h2 class="section-title">热门商品</h2>
        <el-row :gutter="20">
          <el-col
              v-for="product in products"
              :key="product.id"
              :xs="12" :sm="8" :md="6" :lg="4"
          >
            <el-card class="product-card">
              <img
                  :src="product.image"
                  class="product-image"
                  alt="商品图片"
              >
              <div class="product-info">
                <h4 class="product-title">{{ product.name }}</h4>
                <p class="product-price">¥ {{ product.price }}</p>
                <el-button
                    type="primary"
                    size="small"
                    @click="addToCart(product)"
                >
                  加入购物车
                </el-button>
              </div>
            </el-card>
          </el-col>
        </el-row>
      </div>
    </el-main>

    <!-- 页脚 -->
    <el-footer class="main-footer">
      <div class="footer-divider"></div>
      <div class="footer-blocks">
        <el-row :gutter="20" justify="center">
          <el-col
              v-for="(col, index) in footerLinks"
              :key="index"
              :xs="12" :sm="6" :md="4" :lg="3"
          >
            <div class="footer-block">
              <el-icon :size="24" class="block-icon">
                <component :is="col.icon" />
              </el-icon>
              <h4 class="block-title">{{ col.title }}</h4>
              <ul class="block-links">
                <li v-for="(link, i) in col.links" :key="i">
                  <el-link
                      type="info"
                      :underline="false"
                      class="block-link"
                  >
                    {{ link }}
                  </el-link>
                </li>
              </ul>
            </div>
          </el-col>
        </el-row>
      </div>
      <div class="footer-copyright">
        <p>© 2025 易购商城 版权所有</p>
      </div>
    </el-footer>
  </el-container>
</template>

<script>
import { User } from '@element-plus/icons-vue'
import {parseToken} from "@/Utils/auth";
import CartUtils from '@/Utils/car'
export default {
  components: {
    User
  },
  data() {
    return {
      searchKeyword: '',
      isLoggedIn: false,
      userInfo: null,
      categories: [
        { name: '数码电子', icon: 'iphone', color: '#409EFF' ,id:1},
        { name: '服装服饰', icon: 'suitcase', color: '#F56C6C', id:2},
        { name: '家居生活', icon: 'house', color: '#67C23A',id:3 },
        { name: '美妆护肤', icon: 'present', color: '#E6A23C',id:4 },
        { name: '图书音像', icon: 'notebook', color: '#909399',id:5 },
        { name: '冷冻生鲜', icon: 'chicken', color: '#909399',id:6 }
      ],
      products: [

      ],
      footerLinks: [
        {
          title: '消费者服务',
          icon: 'Service',
          links: ['购物指南', '售后服务', '人工客服']
        },
        {
          title: '商家服务',
          icon: 'Shop',
          links: ['合作招商', '商家入驻', '广告服务']
        },
        {
          title: '关于我们',
          icon:  'InfoFilled',
          links: ['公司简介', '加入我们', '联系我们']
        },
        {
          title: '特色服务',
          icon: 'Promotion',
          links: ['企业采购', '会员特权', '全球购']
        }
      ],
        // 更多页脚链接数据...

    }
  },

  methods: {
    async fetchHotProducts() {
      try {
        const randomIds = this.generateRandomIds(6, 10001, 10050);
        const requests = randomIds.map(id =>
            fetch(`${process.env.VUE_APP_API_BASE_URL}/api/goods?id=${id}`)
                .then(response => {
                  if (!response.ok) throw new Error('请求失败');
                  return response.json();
                })
                .catch(error => {
                  console.error('获取商品失败:', error);
                  return null;
                })
        );

        const responses = await Promise.all(requests);
        this.products = responses
            .filter(res => res !== null)
            .map(res => ({
              id: res.id,
              name: res.name,
              price: res.price,
              image: `${process.env.VUE_APP_IMG_BASE_URL}/${res.image}`
            }))
            .slice(0, 6);
      } catch (error) {
        console.error('获取商品失败:', error);
      }
    },
    // 生成随机ID工具方法
    generateRandomIds(count, min, max) {
      const ids = new Set();
      while(ids.size < count) {
        ids.add(Math.floor(Math.random() * (max - min + 1)) + min);
      }
      return [...ids];
    },
    //加入购物车
    addToCart(product) {
      CartUtils.addToCart(product.id,1)
    },
    checkAuth() {
      const token = localStorage.getItem('token')
      // console.log(localStorage.getItem('token'))
      if (!token){
        return
      }

      try {
        // 解析JWT payload
        const payload = parseToken(token)
        const exp = payload.exp *1000
        // 检查token是否过期
        if (Date.now() > exp) {
          this.clearAuth()
          return
        }
        console.log("进没进来？")
        if( 'user' !== payload.role  || payload.role === null){
          this.isLoggedIn = false
          return
        }

        this.isLoggedIn = true
        this.userInfo = {
          username: payload.nickname,
          avatar: payload.avatar
        }
      } catch (error) {
        console.error('Token解析失败:', error)
        this.clearAuth()
      }
    },
    clearAuth() {
      localStorage.removeItem('token')
      this.isLoggedIn = false
      this.userInfo = null
    },
    handleLogout() {
      this.clearAuth()
      this.$router.push('/login')
    },
    //跳转到对应分类页
    handleToGoods(param){
      this.$router.push({
        path: '/goods',
        query: {
          sort:param
        }
      })
    },
    handleSearch(){
      this.$router.push({path:'/goods',query:{
        search:this.searchKeyword
        }})
    }
  },
  created() {
    this.checkAuth()
    this.fetchHotProducts();
  }
}
</script>

<style scoped>
/* 新增样式 */
.user-actions {
  display: flex;
  align-items: center;
  gap: 15px;
}

.action-buttons {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-left: 15px;
  position: relative;
}

.action-btn {
  padding: 8px 12px;
  transition: all 0.3s ease;
  border-radius: 4px;
  color: #666;
}

.action-btn:hover {
  background: #f5f7fa;
  color: #409EFF;
  transform: translateY(-1px);
}

.action-btn i {
  margin-right: 5px;
  font-size: 16px;
}
.user-actions {
  display: flex;
  align-items: center;
  gap: 20px;
}

.user-panel {
  text-align: center;
  padding: 10px;
}

.user-panel p {
  margin-bottom: 10px;
}

ul,ol {
  list-style: none;    /* 移除项目符号 */
  padding-left: 0;     /* 清除左内边距 */
  margin-left: 0;
  text-align: center;
}
.main-container {
  min-width: 1200px;
}

/* 头部样式 */
.main-header {
  background: #fff;
  box-shadow: 0 2px 12px 0 rgba(0,0,0,0.1);
  position: fixed;
  width: 100%;
  top: 0;
  z-index: 1000;
}

.header-content {
  display: flex;
  align-items: center;
  max-width: 1200px;
  margin: 0 auto;
  margin-top: 13px;
}

.logo {
  margin-right: 40px;
}

.search-box {
  flex: 1;
  max-width: 600px;
}

.user-actions {
  margin-left: auto;
  display: flex;
  align-items: center;
  gap: 20px;
}

.section-title {
  font-size: 24px;
  color: #333;
  margin: 40px 0 30px;
  position: relative;
  padding-left: 15px;
}

.section-title::before {
  content: "";
  position: absolute;
  left: 0;
