  margin-bottom: 20px;
}

/* 新增样式优化 */
.product-card {
  transition: all 0.3s ease;
  margin-bottom: 20px;
  border-radius: 8px;
  overflow: hidden;
}

.product-card:hover {
  transform: translateY(-5px);
  box-shadow: 0 10px 20px rgba(0,0,0,0.1);
}

.product-image {
