  height: 200px;
  object-fit: cover;
  border-bottom: 1px solid #eee;
}

.product-info {
  padding: 15px;
  text-align: center;
}
.product-title {
  font-size: 14px;
  height: 40px;
  overflow: hidden;
  text-overflow: ellipsis;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
}

.product-price {
  color: #ff4444;
  font-size: 18px;
  font-weight: bold;
  margin: 10px 0;
}

/* 页脚样式 */
.main-footer {
  background: #fff;
  padding: 30px 20px 0;
  position: relative;
}
.footer-divider {
  height: 1px;
  background: linear-gradient(90deg,
  rgba(255,255,255,0) 0%,
  #ddd 50%,
  rgba(255,255,255,0) 100%
  );
  margin: 0 auto 30px;
  width: 90%;
}
.footer-blocks {
  max-width: 1200px;
  margin: 0 auto;
}

.footer-block {
  text-align: center;
  padding: 15px;
  transition: all 0.3s ease;
  border-radius: 8px;
}

.footer-block:hover {
  background: #f8f8f8;
}

.block-icon {
  color: #666;
  margin-bottom: 10px;
}

.block-title {
  color: #333;
  font-size: 15px;
  margin-bottom: 12px;
  font-weight: 500;
}

.block-links {
  list-style: none;
  padding: 0;
  margin: 0;
}

.block-link {
  color: #666 !important;
  font-size: 13px;
  line-height: 2;
  transition: all 0.2s ease;
}

.block-link:hover {
  color: #ff5000 !important;
  padding-left: 3px;
}
footer-copyright {
  text-align: center;
  padding: 20px 0;
  margin-top: 30px;
  border-top: 1px solid #eee;
}

.footer-copyright p {
  color: #999;
  font-size: 12px;
  margin: 0;
}

@media (max-width: 768px) {
  .footer-block {
    margin-bottom: 20px;
  }

  .block-title {
    font-size: 14px;
  }

  .block-link {
    font-size: 12px;
  }
}

.copyright {
  text-align: center;
  color: #909399;
  margin-top: 20px;
}
</style>