<!-- GoodsPage.vue -->
<template>
  <div class="goods-page-container">
    <el-header class="goods-header">
      <div class="header-content">
        <SearchZone />
        <div class="user-actions">
          <!-- 如果需要可以添加用户相关操作 -->
        </div>
      </div>
    </el-header>
    <goods-sort @filter-change="handleFilterChange"
                :current-category="filterParams.category"/>

    <el-row :gutter="20" class="goods-list">
      <el-col
          v-for="(item, index) in goodsList"
          :key="index"
          :xs="12"
          :sm="8"
          :md="6"
          :lg="4"
      >
        <goods-card :goods-data="item" @add-to-cart="handleAddToCart" />
      </el-col>
    </el-row>

    <pagination-control
        :current-page="pagination.current"
        :page-size="pagination.size"
        :total="pagination.total"
        @page-change="handlePageChange"
        class="pagination-control"
    />
  </div>
</template>

<script setup>
import {ref, reactive, onMounted,  watch} from 'vue'
import { ElMessage } from 'element-plus'
import { useRoute,useRouter } from 'vue-router'
import GoodsSort from '@/components/GoodsSort.vue'
import GoodsCard from '@/components/GoodsCard.vue'
import PaginationControl from '@/components/PaginationControl.vue'
import CartUtils from "@/Utils/car";
import SearchZone from "@/components/SearchZone.vue";

const route = useRoute()
const router = useRouter()
const searchKeyWords =ref('')
const goodsList = ref([])
const pagination = reactive({
  current: 1,
  size: 20,
  total: 0
})

// const filterSearchKeywords = computed(()=>{
//   if (searchKeyWords.value === null) {
//
//     return goodsList.value
//   }
//   return goodsList.value.filter(g=> g.name.toLowerCase().includes(searchKeyWords.value)
//   )
// })

const filterParams = reactive({
  category: '',
  sortType: 'default'
})

const fetchGoods = async (params) => {
  try {
    const response = await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/goods/sort?sort=${params}`)
    if (!response.ok) throw new Error('获取商品失败')
    const data = await response.json()
    goodsList.value = data.map(item => ({
      ...item,
      hot: Math.floor(Math.random() * 10000),
      image: `${process.env.VUE_APP_IMG_BASE_URL}/${item.image}`
    }))
    pagination.total = goodsList.value.length
  } catch (e) {
    ElMessage.error(e.message)
  }
}

const handlePageChange = (page) => {
  pagination.current = page
  fetchGoods(filterParams.category)
}

const handleFilterChange = (params) => {
  // Object.assign(filterParams, params)
  // pagination.current = 1
  // fetchGoods(params.category)
  Object.assign(filterParams, params)
  router.push({
    path: '/goods',
    query: {
      ...route.query, // 保留搜索参数
      sort: params.category || undefined
    }
  })
  fetchGoods(params.category)
}

const handleAddToCart = (goods) => {
  // 实现加入购物车逻辑
  CartUtils.addToCart(goods.id,1,goods.name)
}


onMounted(() => {
  searchKeyWords.value = route.query.search
  const sort = route.query.sort
  if (sort) Object.assign(filterParams, { category: sort })
  fetchGoods(sort || 'all')
})
// 监听路由参数变化
watch(
    () => route.query.search,
    (newVal) => {
      searchKeyWords.value = newVal || ''
    }
)
</script>

<style scoped>
.goods-page-container {
  max-width: 1200px;
  margin: 20px auto;
  padding: 30px;
  background: #fff;
  border-radius: 12px;
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.06);
}

.goods-list {
  margin: 25px 0;
  min-height: 600px;
}

.pagination-control {
  margin-top: 30px;
  padding-top: 20px;
  border-top: 1px solid #eee;
}
.goods-header {
  background: #fff;
  box-shadow: 0 2px 12px rgba(0,0,0,0.06);
  margin-bottom: 20px;
}

.goods-page-container .header-content {
  display: flex;
  align-items: center;
  justify-content: space-between;
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 20px;
  height: 60px;
}
</style>