<template>
  <div class="admin-container">
    <!-- 侧边导航 -->
    <el-aside width="200px" class="admin-sidebar">
      <div class="sidebar-logo">管理后台</div>
      <el-menu
          :default-active="activeMenu"
          @select="handleMenuSelect"
          background-color="#304156"
          text-color="#bfcbd9"
          active-text-color="#409EFF"
      >
        <el-menu-item index="dashboard">
          <el-icon><DataAnalysis /></el-icon>
          <span>数据概览</span>
        </el-menu-item>
        <el-menu-item index="stores">
          <el-icon><Shop /></el-icon>
          <span>店铺管理</span>
        </el-menu-item>
      </el-menu>
    </el-aside>

    <!-- 主内容区 -->
    <div class="admin-main">
      <!-- 顶部栏 -->
      <el-header class="admin-header">
        <div class="header-actions">
          <el-button type="danger" @click="handleLogout">退出登录</el-button>
        </div>
      </el-header>

      <!-- 内容区 -->
      <el-main>
        <!-- 数据概览 -->
        <div v-show="activeMenu === 'dashboard'" class="dashboard-container">
          <!-- 实时数据卡片 -->
          <el-row :gutter="20" class="stats-row">
            <el-col
                :xs="24"
                :sm="12"
                :md="8"
                :lg="6"
                v-for="item in realtimeStats"
                :key="item.title"
            >
              <el-card class="stat-card" shadow="hover">
                <div class="stat-content">
                  <div class="stat-icon" :style="{ backgroundColor: item.color }">
                    <el-icon :size="24"><component :is="item.icon" /></el-icon>
                  </div>
                  <div class="stat-info">
                    <div class="stat-value">{{ item.value }}</div>
                    <div class="stat-title">{{ item.title }}</div>
                    <div
                        class="stat-trend"
                        :style="{ color: item.trend > 0 ? '#67C23A' : '#F56C6C' }"
                    >
                      <el-icon :name="item.trend > 0 ? 'CaretTop' : 'CaretBottom'" />
                      {{ Math.abs(item.trend).toFixed(1) }}%
                    </div>
                  </div>
                </div>
              </el-card>
            </el-col>
          </el-row>

          <!-- 图表区 -->
          <el-row :gutter="20" class="chart-row">
            <!-- 销售趋势 -->
            <el-col :span="24" :lg="12">
              <el-card class="chart-card">
                <div class="chart-header">
                  <h3>销售趋势</h3>
                  <el-select v-model="timeRange" @change="updateCharts">
                    <el-option label="最近7天" value="7"></el-option>
                    <el-option label="最近30天" value="30"></el-option>
                  </el-select>
                </div>
                <div id="salesChart" style="height: 400px"></div>
              </el-card>
            </el-col>

            <!-- 流量分析 -->
            <el-col :span="24" :lg="12">
              <el-card class="chart-card">
                <h3>流量来源</h3>
                <div id="sourceChart" style="height: 400px"></div>
              </el-card>
            </el-col>

            <!-- 商品分布 -->
            <el-col :span="24" :lg="12">
              <el-card class="chart-card">
                <h3>商品类目分布</h3>
                <div id="categoryChart" style="height: 300px"></div>
              </el-card>
            </el-col>

            <!-- 实时订单 -->
            <el-col :span="24" :lg="12">
              <el-card class="chart-card">
                <h3>实时订单监控</h3>
                <div id="realtimeChart" style="height: 300px"></div>
              </el-card>
            </el-col>
          </el-row>
        </div>

        <!-- 店铺管理 -->
        <div v-show="activeMenu === 'stores'">
          <div class="toolbar">
            <el-button type="primary" @click="showStoreDialog">+ 添加店铺</el-button>
          </div>

          <el-table :data="stores" style="width: 100%;height: 420px">
            <!-- 调整表格列匹配后端数据 -->
            <el-table-column prop="store_id" label="店铺ID" />
            <el-table-column prop="login_code" label="登录代码" />
            <el-table-column prop="owner" label="店主" />
            <el-table-column prop="brand" label="品牌" />
            <el-table-column prop="phone" label="联系方式" />
            <el-table-column prop="createTime" label="创建时间" />
            <el-table-column label="操作" width="150">
              <template #default="{ row }">
                <el-button type="text" @click="handleEdit(row)">编辑</el-button>
                <el-button
                    type="text"
                    style="color: #F56C6C"
                    @click="handleDelete(row.store_id)"
                >
                  删除
                </el-button>
              </template>
            </el-table-column>
          </el-table>
        </div>
      </el-main>
    </div>

    <!-- 添加店铺对话框 -->
    <el-dialog
        :title="editMode ? '编辑店铺' : '添加店铺'"
        v-model="showStoreForm"
        width="500px"
    >
      <el-form :model="storeForm" :rules="storeRules" label-width="80px">
        <el-form-item label="登录代码" prop="login_code">
          <el-input v-model="storeForm.login_code" />
        </el-form-item>
        <el-form-item label="店主" prop="owner">
          <el-input v-model="storeForm.owner" />
        </el-form-item>
        <el-form-item label="品牌" prop="brand">
          <el-input v-model="storeForm.brand" />
        </el-form-item>
        <el-form-item label="手机号" prop="phone">
          <el-input v-model="storeForm.phone" />
        </el-form-item>
      </el-form>
      <template #footer>
        <el-button @click="showStoreForm = false">取消</el-button>
        <el-button type="primary" @click="submitStore">提交</el-button>
      </template>
    </el-dialog>
  </div>
</template>

<script setup>
import { ref, onMounted, onBeforeUnmount } from 'vue'
import { useRouter } from 'vue-router'
import {ElMessage, ElMessageBox} from 'element-plus'
import * as echarts from 'echarts'
import {parseToken} from "@/Utils/auth";

const router = useRouter()

// Token验证
const checkAuth = () => {
  const token = localStorage.getItem('token')
  const payload = parseToken(token)
  if (!token || payload.role !== 'admin') {
    router.push('/login')
  }
  // 实际项目中应验证token有效性
}

// 菜单管理
const activeMenu = ref('dashboard')
const handleMenuSelect = (key) => {
  activeMenu.value = key
}

// 实时数据模拟
const generateData = (base, range) =>
    Array.from({length: 7}, () => Math.floor(base + Math.random() * range))

const realtimeStats = ref([
  {
    title: '今日订单',
    value: '1,234',
    icon: 'ShoppingCart',
    color: '#409EFF',
    trend: 2.3
  },
  {
    title: '在线用户',
    value: '2,345',
    icon: 'User',
    color: '#67C23A',
    trend: 5.1
  },
  {
    title: '销售额',
    value: '¥ 89,230',
    icon: 'Money',
    color: '#E6A23C',
    trend: -1.2
  },
  {
    title: '转化率',
    value: '3.24%',
    icon: 'DataAnalysis',
    color: '#F56C6C',
    trend: 0.8
  }
])

// 图表实例和配置
let salesChart = null
let sourceChart = null
let categoryChart = null
let realtimeChart = null
let intervalId = null
const timeRange = ref('7')

// 初始化图表
const initCharts = () => {
  // 销售趋势图
  salesChart = echarts.init(document.getElementById('salesChart'))
  salesChart.setOption({
    tooltip: { trigger: 'axis' },
    legend: { data: ['订单量', '销售额'] },
    xAxis: {
      type: 'category',
      data: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun']
    },
    yAxis: [{
      type: 'value',
      name: '订单量'
    }, {
      type: 'value',
      name: '销售额',
      axisLabel: { formatter: '¥{value}' }
    }],
    series: [
      {
        name: '订单量',
        type: 'bar',
        data: generateData(100, 50),
        itemStyle: { color: '#409EFF' }
      },
      {
        name: '销售额',
        type: 'line',
        yAxisIndex: 1,
        data: generateData(10000, 5000),
        smooth: true,
        lineStyle: { color: '#E6A23C' }
      }
    ]
  })

  // 流量来源图
  sourceChart = echarts.init(document.getElementById('sourceChart'))
  sourceChart.setOption({
    tooltip: { trigger: 'item' },
    series: [{
      type: 'pie',
      radius: ['40%', '70%'],
      data: [
        { value: 1048, name: '直接访问' },
        { value: 735, name: '搜索引擎' },
        { value: 580, name: '社交媒体' },
        { value: 484, name: '邮件营销' }
      ],
      itemStyle: {
        borderRadius: 10,
        color: params => ['#409EFF', '#67C23A', '#E6A23C', '#F56C6C'][params.dataIndex]
      }
    }]
  })

  // 类目分布图
  categoryChart = echarts.init(document.getElementById('categoryChart'))
  categoryChart.setOption({
    tooltip: { trigger: 'item' },
    series: [{
      type: 'pie',
      radius: ['50%', '70%'],
      data: [
        { value: 1048, name: '数码电子' },
        { value: 735, name: '服饰箱包' },
        { value: 580, name: '家居日用' },
        { value: 484, name: '美妆个护' }
      ],
      itemStyle: {
        borderRadius: 10,
        color: params => ['#409EFF', '#67C23A', '#E6A23C', '#F56C6C'][params.dataIndex]
      }
    }]
  })

  // 实时订单图
  realtimeChart = echarts.init(document.getElementById('realtimeChart'))
  const initialData = Array.from({length: 20}, () => Math.floor(Math.random() * 100))
  realtimeChart.setOption({
    xAxis: { type: 'category', show: false },
    yAxis: { type: 'value', max: 100 },
    series: [{
      data: initialData,
      type: 'line',
      smooth: true,
      lineStyle: { color: '#67C23A' },
      areaStyle: { color: '#67C23A20' }
    }]
  })
}

// 更新图表数据
const updateCharts = () => {
  salesChart.setOption({
    series: [{
      data: generateData(timeRange.value === '7' ? 100 : 300, 50)
    },{
      data: generateData(timeRange.value === '7' ? 10000 : 30000, 5000)
    }]
  })
}

// 启动实时更新
const startRealtimeUpdate = () => {
  intervalId = setInterval(() => {
    // 更新实时图表
    const oldData = realtimeChart.getOption().series[0].data
    const newData = [...oldData.slice(1), Math.random() * 100]
    realtimeChart.setOption({ series: [{ data: newData }] })

    // 更新统计指标
    realtimeStats.value = realtimeStats.value.map(stat => ({
      ...stat,
      value: stat.title === '今日订单' ?
          `${Math.floor(1234 + Math.random() * 50)}` : stat.value,
      trend: parseFloat((stat.trend + (Math.random() - 0.5)).toFixed(1))
    }))
  }, 3000)
}

// 店铺管理
const showStoreForm = ref(false)
const editMode = ref(false) // 新增编辑模式标识
const currentStoreId = ref('') // 新增当前编辑店铺ID
const storeForm = ref({
  store_id:'',
  name: '',
  description: '',
  address: '',
  owner: '',
  brand: '',
  phone: ''
})
const stores = ref()
const storeRules = {
  login_code: [{ required: true, message: '请输入登录代码', trigger: 'blur' }],
  owner: [{ required: true, message: '请输入店主姓名', trigger: 'blur' }],
  brand: [{ required: true, message: '请输入品牌名称', trigger: 'blur' }],
  phone: [
    { required: true, message: '请输入联系方式', trigger: 'blur' },
    { pattern: /^1[3-9]\d{9}$/, message: '手机号格式不正确', trigger: 'blur' }
  ]
}

// 编辑店铺（新增方法）
const handleEdit = (store) => {
  editMode.value = true
  currentStoreId.value = store.store_id
  storeForm.value = {
    store_id: store.store_id,
    login_code: store.login_code,
    owner: store.owner,
    brand: store.brand,
    phone: store.phone
  }
  showStoreForm.value = true
}



const handleDelete = async (storeId) => {
  try {
    await ElMessageBox.confirm('确认删除该店铺？', '警告', {
      confirmButtonText: '确认',
      cancelButtonText: '取消',
      type: 'warning'
    })

    const response = await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/store/delete`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ storeId })
    })

    if (!response.ok) throw new Error('删除失败')

    ElMessage.success('删除成功')
    fetchStores()
  } catch (error) {
    if (error !== 'cancel') {
      ElMessage.error(error.message)
    }
  }
}
const fetchStores = async () => {
  try {
    const response = await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/store/all`)
    if (!response.ok) throw new Error('请求失败')
    const data = await response.json()
    stores.value = data.map(store => ({
      ...store,
      createTime: new Date(store.create_time).toLocaleDateString()
    }))
  } catch (error) {
    ElMessage.error('获取店铺列表失败')
  }
}
// 显示添加对话框（修改原有方法）
const showStoreDialog = () => {
  editMode.value = false
  storeForm.value = { login_code: '', owner: '', brand: '', phone: '' }
  showStoreForm.value = true
}
const submitStore = async () => {
  try {
    const url = editMode.value
        ? `${process.env.VUE_APP_API_BASE_URL}/api/store/update`
        : `${process.env.VUE_APP_API_BASE_URL}/api/store/add`

    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(storeForm.value)
    })

    if (!response.ok) {
      const errorData = await response.json()
      throw new Error(errorData.message || '操作失败')
    }

    ElMessage.success(editMode.value ? '更新成功' : '添加成功')
    fetchStores()
    showStoreForm.value = false
  } catch (error) {
    ElMessage.error(error.message)
  }
}

const handleLogout = () => {
  localStorage.removeItem('token')
  router.push('/')
}

onMounted(() => {
  checkAuth()
  initCharts()
  startRealtimeUpdate()
  fetchStores()
  window.addEventListener('resize', () => {
    [salesChart, sourceChart, categoryChart, realtimeChart].forEach(chart => chart.resize())
  })
})

onBeforeUnmount(() => {
  clearInterval(intervalId)
  window.removeEventListener('resize', () => {
    [salesChart, sourceChart, categoryChart, realtimeChart].forEach(chart => chart.resize())
  })
})
</script>

<style scoped>
.admin-container {
  display: flex;
  min-height: 100vh;
  background: #f0f2f5;
}

.admin-sidebar {
  background: #304156;
  box-shadow: 2px 0 6px rgba(0, 0, 0, 0.1);
}

.sidebar-logo {
  height: 60px;
  line-height: 60px;
  text-align: center;
  color: #fff;
  font-size: 18px;
  background: #2b2f3a;
}

.admin-main {
  flex: 1;
  overflow: hidden;
}

.admin-header {
  background: #fff;
  border-bottom: 1px solid #e6ebf5;
  display: flex;
  align-items: center;
  justify-content: flex-end;
  padding: 0 20px;
}

.dashboard-container {
  padding: 20px;
}

.stats-row {
  margin-bottom: 20px;
}

.stat-card {
  margin-bottom: 20px;
  transition: transform 0.3s;
  border-radius: 12px;
}

.stat-card:hover {
  transform: translateY(-5px);
}

.stat-content {
  display: flex;
  align-items: center;
  padding: 20px;
}

.stat-icon {
  width: 48px;
  height: 48px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
  margin-right: 16px;
}

.stat-info {
  flex: 1;
}

.stat-value {
  font-size: 20px;
  font-weight: 600;
  color: #303133;
}

.stat-title {
  color: #909399;
  font-size: 14px;
  margin: 4px 0;
}

.stat-trend {
  font-size: 12px;
  display: flex;
  align-items: center;
  gap: 4px;
}

.chart-card {
  margin-bottom: 20px;
  border-radius: 12px;
}

.chart-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
  padding: 0 20px;
}

.chart-card h3 {
  color: #303133;
  margin: 0;
}

.toolbar {
  margin-bottom: 20px;
}

:deep(.el-menu) {
  border-right: none;
}

:deep(.el-menu-item) {
  height: 56px;
  line-height: 56px;
}
</style>