<template>
  <el-form :model="form" :rules="rules" ref="formRef">
    <el-form-item prop="storeId">
      <el-input
          v-model="form.storeId"
          placeholder="请输入商家ID"
          class="custom-input"
      >
        <template #prefix>
          <el-icon class="input-icon"><OfficeBuilding /></el-icon>
        </template>
      </el-input>
    </el-form-item>

    <el-form-item prop="loginCode">
      <el-input
          v-model="form.loginCode"
          type="password"
          placeholder="请输入登录码"
          show-password
          class="custom-input"
      >
        <template #prefix>
          <el-icon class="input-icon"><Key /></el-icon>
        </template>
      </el-input>
    </el-form-item>

    <el-form-item>
      <el-button
          type="primary"
          class="login-btn"
          :loading="loading"
          @click="submitForm"
      >
        {{ loading ? '登录中...' : '商家登录' }}
      </el-button>
    </el-form-item>
  </el-form>
</template>

<script setup>
import { ref } from 'vue'
import { ElMessage } from 'element-plus'
import { useRouter } from 'vue-router'
import {parseToken} from "@/Utils/auth";


const router = useRouter()
const form = ref({
  storeId: '',
  loginCode: ''
})
const formRef = ref(null)
const loading = ref(false)

const validateStoreId = (rule, value, callback) => {
  if (!/^\d{1,12}$/.test(value)) {
    callback(new Error('商家ID应为6-12位数字'))
  } else {
    callback()
  }
}

const validateLoginCode = (rule, value, callback) => {
  if (value.length < 8 || !/[A-Z]/.test(value) || !/\d/.test(value)) {
    callback(new Error('登录码需8位且包含大写字母和数字'))
  } else {
    callback()
  }
}

const rules = {
  storeId: [{ validator: validateStoreId, trigger: 'blur' }],
  loginCode: [{ validator: validateLoginCode, trigger: 'blur' }]
}

const submitForm = async () => {
  try {
    // await formRef.value.validate()
    loading.value = true
    console.log("1")

    const response = await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/storeLogin`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        store_id:form.value.storeId,
        login_code:form.value.loginCode,
      })
    })

    const data = await response.json()
    console.log("2")
    if (response.status === 200) {
      localStorage.setItem('token', data.token)

      // 解析token payload
      const payload = parseToken(data.token)
      if (payload) {
        localStorage.setItem('storeId', payload.storeId)
        localStorage.setItem('storeName', payload.storeName)
        router.push('/store')
      }
      ElMessage.success('商家登录成功')
    } else {
      ElMessage.error(data.message || '登录失败')
    }
  } catch (error) {
    ElMessage.error(error.message || '网络请求失败')
  } finally {
    loading.value = false
  }
}
</script>