<template>
  <div class="shopcar-container">
    <!-- 购物车头部 -->
    <div class="cart-header">
      <div class="header-left">
        <h2 class="header-title">
          <el-icon><ShoppingCart /></el-icon>我的购物车
        </h2>
        <el-checkbox v-model="selectAll" @change="handleSelectAll" class="select-all">
          <span class="select-all-text">全选</span>
        </el-checkbox>
      </div>

      <!-- 新增用户信息展示 -->
      <div class="user-info" v-if="nickname">
        <el-icon><User /></el-icon>
        <span class="username">{{ nickname }}</span>
      </div>
    </div>


    <!-- 商品列表 -->
    <div class="cart-scroll-area">
      <el-table
          :data="cartItems"
          style="width: 100%"
          class="cart-table"
          :height="tableHeight"
      >
        <!-- 选择列 -->
        <el-table-column width="60" align="center">
          <template #default="{ row }">
            <el-checkbox
                v-model="row.selected"
                class="item-checkbox"
            />
          </template>
        </el-table-column>

        <!-- 商品图片 -->
        <el-table-column width="160">
          <template #default="{ row }">
            <router-link :to="`/goods/${row.id}`" class="goods-image-wrapper">
              <el-image
                  :src="row.image"
                  fit="cover"
                  class="goods-image"
                  :preview-src-list="[row.image]"
              />
            </router-link>
          </template>
        </el-table-column>
        <!-- 商品信息 -->
        <el-table-column label="商品信息">
          <template #default="{ row }">
            <div class="goods-info">
              <div class="name">{{ row.name }}</div>
              <div class="shop">
                <el-icon><Shop /></el-icon>
                <span>{{ row.shop }}</span>
              </div>
            </div>
          </template>
        </el-table-column>

        <!-- 单价 -->
        <el-table-column label="单价" width="140" align="center">
          <template #default="{ row }">
            <span class="price">¥{{ row.price.toFixed(2) }}</span>
          </template>
        </el-table-column>

        <!-- 数量 -->
        <el-table-column label="数量" width="160" align="center">
          <template #default="{ row }">
            <el-input-number
                v-model="row.quantity"
                :min="1"
                size="small"
                controls-position="right"
                class="quantity-input"
                @change="(val) => handleQuantityChange(val, row)"
            />
          </template>
        </el-table-column>

        <!-- 小计 -->
        <el-table-column label="小计" width="140" align="center">
          <template #default="{ row }">
            <span class="subtotal">¥{{ (row.price * row.quantity).toFixed(2) }}</span>
          </template>
        </el-table-column>

        <!-- 操作 -->
        <el-table-column label="操作" width="100" align="center">
          <template #default="{ row }">
            <el-button
                type="danger"
                link
                class="delete-btn"
                @click="removeItem(row)"
            >
              <el-icon><Delete /></el-icon>
              删除
            </el-button>
          </template>
        </el-table-column>
      </el-table>
    </div>


    <!-- 底部结算栏 -->
    <div class="cart-footer fixed-footer">
      <div class="total-info">
        <span class="selected-count">已选 {{ selectedCount }} 件商品</span>
        <span class="total-text">合计：</span>
        <span class="total-price">¥{{ totalPrice.toFixed(2) }}</span>
      </div>
      <el-button
          type="danger"
          size="large"
          class="settle-btn"
          :disabled="selectedCount === 0"
          @click="handleSettlement"
      >
        去结算 ({{ selectedCount }})
      </el-button>
    </div>

    <!-- 结算弹窗 -->
    <SettlementDialog
        v-model="showDialog"
        :selected-items="selectedItems"
        :user-id="userId"
        :total-price="totalPrice"
        :selected-count="selectedCount"
        :car-id="carId"
        @success="handleOrderSuccess"
    />
  </div>
</template>

<script setup>
import { ref, computed, onMounted } from 'vue'
import { parseToken } from "@/Utils/auth"
import { ElMessage } from 'element-plus'
import { useRouter } from 'vue-router'
import CartUtils from "@/Utils/car";
import SettlementDialog from '@/components/SettlementDialog.vue'
import HttpUtils from '@/Utils/HttpRequest'
const router = useRouter()

// 用户购物车状态
const cartItems = ref([])
const selectAll = ref(false)
const showDialog = ref(false)
const nickname = ref('')
const userId = ref(null)
const carId = ref(null)
const isLoggedIn = ref(false)

const selectedItems = computed(() =>
    cartItems.value.filter(item => item.selected)
)
// 获取商品详细信息
const fetchGoodsDetails = async (items) => {
  const itemsWithDetails = []
  for (const item of items) {
    try {
      const res = await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/goods?id=${item.goods_id}`)
      const data = await res.json()
      //要规范前后端接口规范格式
      if (res.status === 200) {
        itemsWithDetails.push({
          id:data.id,
          name:data.name,
          image:`${process.env.VUE_APP_IMG_BASE_URL}/`+data.image,
          price:data.price,
          shop:data.shop,
          sort:data.sort,
          quantity: item.quantity,
          selected: false
        })
      }
    } catch (error) {
      console.error('商品信息获取失败:', error.message)
    }
  }
  return itemsWithDetails
}

// 获取购物车数据
const fetchCartData = async () => {
  try {
    if (!isLoggedIn.value) {
      // 未登录用户读取临时购物车
      const tempCart = JSON.parse(localStorage.getItem('temp_car') || '[]')
      cartItems.value = await fetchGoodsDetails(tempCart)
    } else {
      // 已登录用户从后端获取
      const res = await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/car?user_id=${userId.value}&car_id=${carId.value}`,{
          method: 'POST',
          headers: {
        'Content-Type': 'application/json'
      }
    })


      const data = await res.json()
      if (res.status === 200) {
        const backendCart = data.data.goods_list
        cartItems.value =[...backendCart]
        cartItems.value.forEach(c=>{
          c.image = `${process.env.VUE_APP_IMG_BASE_URL}/${c.image}`
        })
        // localStorage.setItem('user_car', JSON.stringify(ids))

      }

    }
  } catch (error) {
    ElMessage.error('购物车数据获取失败')
  }
}

// 初始化用户信息
const initUser = async () => {
  const token = localStorage.getItem('token')
  if (token) {
    try {
      const payload = parseToken(token)
      if (payload.role === 'user') {
        isLoggedIn.value = true
        userId.value = payload.phone
        nickname.value = payload.nickname || '用户'
        // 获取购物车ID并同步数据
        await fetchCarId()
        return
      }
    } catch (e) {
      console.error('token解析失败:', e.message)
    }
  }
  isLoggedIn.value = false
  await fetchCartData()
}

// 获取购物车ID并合并本地数据
const fetchCarId = async () => {
  try {

    const res = await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/car/getCarId?user_id=${userId.value}`)
    const data = await res.json()

    if (res.status === 200) {
      carId.value = data.data.car_id
      // 合并本地购物车数据到后端
      await syncLocalCartToServer()
      // 获取最新数据
      await fetchCartData()


    }
  } catch (error) {
    ElMessage.error(`购物车ID获取失败:`,error.message)
  }
}
// const  syncTempCarToUserCar = async () =>{
//   try {
//     // localStorage.removeItem("temp_car")
//     ElMessage.success("同步临时购物车成功")
//   }catch (error){
//     ElMessage.error(`同步临时购物车失败：${error}`)
//   }
//
// }
// 同步本地购物车到服务器
const syncLocalCartToServer = async () => {
  // const localCart = JSON.parse(localStorage.getItem('user_car') || '[]')
  /**
   * fixme 可能会产生这些问题
   * 1、当未登录时，加入购物车，且购物车内（后端请求得到的）有相同商品，登录后两者数量不会叠加，会以后端的为主
   *
   * 2、对于对于初次没有使用过购物车的用户，储存在localstorage的
   * @param String {user_car} user_car,
   * 解决方案是在fetchCar获取后端购物车数据时加上判断，若返回购物车商品信息为空，则上传当前储存的商品
   */

  const localCart = CartUtils.getUserCart()
  const tempCar = CartUtils.getTempCart()
  const excludeItem = tempCar.map(t => CartUtils.addToCart(t.goods_id,t.quantity))
  excludeItem.forEach(e => console.log(e))
  if (excludeItem.length !== 0) await addNewItemsToServer(excludeItem)
  if (localCart.length === 0){ return}
  localCart.forEach(l => console.log(l))
  try {
    // await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/car/update`, {
    //   method: 'POST',
    //   headers: { 'Content-Type': 'application/json' },
    //   body: JSON.stringify({
    //     user_id: userId.value,
    //     car_id: carId.value,
    //     items: localCart.map(item => ({
    //       goods_id: item.goods_id,
    //       count: item.quantity
    //     }))
    //   })
    // })
    await HttpUtils.post(`${process.env.VUE_APP_API_BASE_URL}/api/car/update`, {
      data: {
        user_id: userId.value,
        car_id: carId.value,
        items: localCart.map(item => ({
          goods_id: item.goods_id,
          count: item.quantity
        }))
      }
    })
    // 清空本地存储
    localStorage.removeItem('user_car')
  }catch (error) {
    ElMessage.error(`数据同步失败:`,error.message)

  }
}

// const mergeCarts = (userCar, tempCar) => {
//   // 1. 创建快速查找表
//   const userMap = new Map(userCar.map(item => [item.goods_id, item]))
//
//   // 2. 克隆原始数组避免污染原数据
//   const merged = userCar.map(item => ({ ...item }))
//
//   // 3. 遍历处理临时购物车
//   const newItems = []
//
//   tempCar.forEach(tempItem => {
//     const tempClone = { ...tempItem }
//
//     if (userMap.has(tempClone.goods_id)) {
//       // 合并数量
//       userMap.get(tempClone.goods_id).quantity += tempClone.quantity
//     } else {
//       // 记录新商品
//       newItems.push(tempClone)
//       merged.push(tempClone)
//       userMap.set(tempClone.goods_id, tempClone)
//     }
//   })
//
//   // return {
//   //   mergedCart: merged,
//   //   newItems: newItems,
//   //   updatedItems: userCar.filter(item =>
//   //       tempCar.some(t => t.goods_id === item.goods_id))
//   // }
//   return {
//     newItems: newItems,
//   }
// }
// 同步本地购物车到服务器
const addNewItemsToServer = async (newItem) => {
  console.log(newItem)
  try {
    await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/car/add`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        user_id: userId.value,
        car_id: carId.value,
        items: newItem.map(item => ({
          goods_id: item.goods_id,
          count: item.quantity
        }))
      })
    })
    console.log(newItem)
    // 清空本地存储
    localStorage.removeItem('temp_car')
  } catch (error) {
    ElMessage.error(`数据同步失败:`,error.message)

  }
}

// 数量修改处理
const handleQuantityChange = async (val, item) => {
  if (isLoggedIn.value) {
    try {
      // 更新后端
      await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/car/update`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          user_id: userId.value,
          car_id: carId.value,
          items: [{ goods_id: item.id, count: val }]
        })
      })

      // 更新本地
      const userCart = CartUtils.getCart()
      const index = userCart.findIndex(i => i.goods_id === item.id)
      if (index !== -1) {
        userCart[index].quantity = val
      }
      console.log(userCart)
      localStorage.setItem('user_car', JSON.stringify(userCart))
    } catch (error) {
      ElMessage.error('数量更新失败')
    }
  } else {
    // 更新临时购物车
    const tempCart = JSON.parse(localStorage.getItem('temp_car') || '[]')
    const index = tempCart.findIndex(i => i.goods_id === item.id)
    if (index !== -1) {
      tempCart[index].quantity = val
    }
    localStorage.setItem('temp_car', JSON.stringify(tempCart))
  }
}

// 删除商品
const removeItem = async (item) => {
  if (isLoggedIn.value) {
    try {
      await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/car/delete`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          user_id: userId.value,
          car_id: carId.value,
          goods_ids: [item.id]
        })
      })
      // 更新本地
      const userCart = CartUtils.getCart()
      localStorage.setItem('user_car', JSON.stringify(userCart.filter(i => i.goods_id !== item.id)))
      console.log('删除完成')

    } catch (error) {
      ElMessage.error('删除失败')
    }
  } else {
    // 更新临时购物车
    const tempCart = JSON.parse(localStorage.getItem('temp_car') || '[]')
    localStorage.setItem('temp_car',
        JSON.stringify(tempCart.filter(i => i.goods_id !== item.id)))

  }
  cartItems.value = cartItems.value.filter(i => i.id !== item.id)

}

// 结算处理
const handleSettlement = () => {
  if (!isLoggedIn.value) {
    router.push('/login')
    return
  }
  showDialog.value = true
}
// 全选处理
const handleSelectAll = (val) => {
  cartItems.value.forEach(item => item.selected = val)
}

// 计算属性
const selectedCount = computed(() => cartItems.value.filter(item => item.selected).length)
const totalPrice = computed(() =>
    cartItems.value.filter(item => item.selected)
        .reduce((sum, item) => sum + item.price * item.quantity, 0)
)

onMounted(initUser)
</script>

