<template>
  <div class="register-container">
    <div class="register-box">
      <div class="register-header">
        <h1 class="title">用户注册</h1>
        <div class="sub-title">开启您的购物之旅</div>
      </div>

      <el-form
          :model="form"
          :rules="rules"
          ref="formRef"
          label-position="top"
          class="register-form"
      >
        <el-form-item label="手机号" prop="phone">
          <el-input
              v-model="form.phone"
              placeholder="请输入11位手机号"
              clearable
              class="custom-input"
          >
            <template #prefix>
              <el-icon class="input-icon"><Iphone /></el-icon>
            </template>
          </el-input>
        </el-form-item>

        <el-form-item label="密码" prop="password">
          <el-input
              v-model="form.password"
              type="password"
              placeholder="至少8位含字母和数字"
              show-password
              class="custom-input"
          >
            <template #prefix>
              <el-icon class="input-icon"><Lock /></el-icon>
            </template>
          </el-input>
        </el-form-item>

        <el-form-item label="确认密码" prop="confirmPassword">
          <el-input
              v-model="form.confirmPassword"
              type="password"
              placeholder="请再次输入密码"
              show-password
              class="custom-input"
          >
            <template #prefix>
              <el-icon class="input-icon"><Unlock /></el-icon>
            </template>
          </el-input>
        </el-form-item>

        <el-form-item>
          <el-button
              type="primary"
              class="register-btn"
              :loading="loading"
              @click="submitForm"
          >
            {{ loading ? '注册中...' : '立即注册' }}
          </el-button>
        </el-form-item>

        <div class="login-link">
          <span>已注册？</span>
          <router-link to="/login">去登录</router-link>
        </div>
      </el-form>
    </div>
  </div>
</template>

<script setup>
import { ref } from 'vue'
import { ElMessage } from 'element-plus'
import { useRouter } from 'vue-router'

const router = useRouter()
const form = ref({
  phone: '',
  password: '',
  confirmPassword: ''
})

const formRef = ref(null)
const loading = ref(false)

// 验证规则
const validatePhone = (rule, value, callback) => {
  if (!/^1[3-9]\d{9}$/.test(value)) {
    callback(new Error('手机号格式不正确'))
  } else {
    callback()
  }
}

const validatePassword = (rule, value, callback) => {
  if (value.length < 8) {
    callback(new Error('密码长度不能少于8位'))
  } else if (!/[a-zA-Z]/.test(value) || !/\d/.test(value)) {
    callback(new Error('需包含字母和数字'))
  } else {
    callback()
  }
}

const validateConfirm = (rule, value, callback) => {
  if (value !== form.value.password) {
    callback(new Error('两次输入密码不一致'))
  } else {
    callback()
  }
}

const rules = {
  phone: [{ validator: validatePhone, trigger: 'blur' }],
  password: [{ validator: validatePassword, trigger: 'blur' }],
  confirmPassword: [{ validator: validateConfirm, trigger: 'blur' }]
}

const submitForm = async () => {
  try {
    const valid = await formRef.value.validate()
    if (!valid) return

    loading.value = true

    const response = await fetch(`${process.env.VUE_APP_API_BASE_URL}/api/registry`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        id: form.value.phone,
        pswd: form.value.password,
        nickname: "temp"
      })
    })

    const data = await response.json()

    if (data.code === 200) {
      ElMessage.success('注册成功')
      router.push('/login')

    } else {
      ElMessage.error(data.msg || `注册失败，请重试:${data.message}`)
    }
  } catch (error) {
    if (form.value.phone === ''
        || form.value.password === ''
        || form.value.confirmPassword === '') {
      ElMessage.warning('请填写完整信息！')
      return
    }
    ElMessage.error('请求失败，请检查网络连接')
  } finally {
    loading.value = false
  }
}
</script>

<style scoped>
.register-container {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
  background: linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%);
}

.register-box {
  width: 450px;
  padding: 40px;
  background: white;
  border-radius: 12px;
  box-shadow: 0 6px 20px rgba(0, 0, 0, 0.1);
}

.register-header {
  text-align: center;
  margin-bottom: 40px;
}

.title {
  color: #303133;
  font-size: 28px;
  margin-bottom: 8px;
}

.sub-title {
  color: #909399;
  font-size: 14px;
}

.register-form {
  :deep(.el-form-item__label) {
    font-weight: 500;
    color: #606266;
  }
}

.register-btn {
  width: 100%;
  height: 48px;
  font-size: 16px;
  margin-top: 10px;
}

.login-link {
  text-align: center;
  margin-top: 20px;
  color: #909399;

  a {
    color: #409eff;
    margin-left: 6px;
    text-decoration: none;

    &:hover {
      color: #66b1ff;
    }
  }
}
</style>