<template>
  <el-dialog
      v-model="visible"
      title="订单结算"
      width="600px"
      class="settle-dialog"
      :before-close="handleClose"
  >
    <!-- 收货信息表单 -->
    <el-form
        ref="formRef"
        :model="formData"
        :rules="formRules"
        label-width="100px"
        label-position="top"
    >
      <!-- 收货地址 -->
      <el-form-item label="收货地址" prop="address">
        <el-input
            v-model="formData.address"
            placeholder="请输入详细收货地址"
            clearable
        />
      </el-form-item>

      <!-- 收货人 -->
      <el-form-item label="收货人" prop="receiver">
        <el-input
            v-model="formData.receiver"
            placeholder="请输入收货人姓名"
            clearable
        />
      </el-form-item>

      <!-- 联系电话 -->
      <el-form-item label="联系电话" prop="phone">
        <el-input
            v-model="formData.phone"
            placeholder="请输入联系电话"
            clearable
            maxlength="11"
        />
      </el-form-item>

      <!-- 支付方式 -->
      <el-form-item label="支付方式" prop="payment">
        <el-select
            v-model="formData.payment"
            placeholder="请选择支付方式"
            class="full-width"
        >
          <el-option
              v-for="item in paymentOptions"
              :key="item.value"
              :label="item.label"
              :value="item.value"
          />
        </el-select>
      </el-form-item>

      <!-- 订单摘要 -->
      <div class="order-summary">
        <div class="summary-item">
          <span class="label">商品总数：</span>
          <span class="value">{{ selectedCount }}件</span>
        </div>
        <div class="summary-item total">
          <span class="label">应付总额：</span>
          <span class="value">¥{{ totalPrice.toFixed(2) }}</span>
        </div>
      </div>
    </el-form>

    <template #footer>
      <div class="dialog-footer">
        <el-button @click="visible = false">取 消</el-button>
        <el-button
            type="primary"
            :loading="submitting"
            @click="handleSubmit"
        >
          确认结算
        </el-button>
      </div>
    </template>
  </el-dialog>
</template>

<script setup>
import { ref, watch } from 'vue'
import { ElMessage } from 'element-plus'
import HttpUtils from '@/Utils/HttpRequest'
import CartUtils from "@/Utils/car";

const props = defineProps({
  // 是否显示弹窗
  modelValue: Boolean,
  // 选中的商品列表
  selectedItems: {
    type: Array,
    default: () => []
  },
  // 用户ID
  userId: [String, Number],
  // 订单总金额
  totalPrice: Number,
  // 选中的商品数量
  selectedCount: Number,
  //购物车iD
  carId:String
})

const emit = defineEmits(['update:modelValue', 'success'])

// 表单引用
const formRef = ref(null)
// 是否显示弹窗
const visible = ref(false)
// 是否正在提交
const submitting = ref(false)

// 支付方式选项
const paymentOptions = [
  { value: 1, label: '支付宝支付' },
  { value: 2, label: '微信支付' },
  { value: 3, label: '银联支付' }
]

// 表单数据
const formData = ref({
  address: '',
  receiver: '',
  phone: '',
  payment: null
})

// 表单验证规则
const formRules = {
  address: [
    { required: true, message: '请输入收货地址', trigger: 'blur' },
    { min: 5, message: '地址最少5个字符', trigger: 'blur' }
  ],
  receiver: [
    { required: true, message: '请输入收货人姓名', trigger: 'blur' },
    { min: 2, message: '姓名最少2个字符', trigger: 'blur' }
  ],
  phone: [
    { required: true, message: '请输入联系电话', trigger: 'blur' },
    { pattern: /^1[3-9]\d{9}$/, message: '请输入正确的手机号码', trigger: 'blur' }
  ],
  payment: [
    { required: true, message: '请选择支付方式', trigger: 'change' }
  ]
}

// 监听显隐状态变化
watch(() => props.modelValue, val => {
  visible.value = val
})

// 弹窗关闭处理
const handleClose = () => {
  emit('update:modelValue', false)
}
//提交订单后删除购物车物品（后端）
const deleteCarItem =   (car_id,goods) => {
  return HttpUtils.post(`${process.env.VUE_APP_API_BASE_URL}/api/car/delete`,{
    data:{car_id:car_id,user_id:props.userId,goods_ids:Array.from(goods,(g=> g.goods_id ))}
  })
}

// 提交订单
const handleSubmit = async () => {
  try {
    // 验证表单
    await formRef.value.validate()
    submitting.value = true
    // 构造订单数据
    const orderData = {
      user_id: props.userId,
      total_amount: props.totalPrice,
      payment_method: formData.value.payment,
      address: formData.value.address,
      receiver: formData.value.receiver,
      phone: formData.value.phone,
      goods: props.selectedItems.map(item => ({
        goods_id: item.id,
        quantity: item.quantity,
        price: item.price
      }))
    }
    // 提交订单
    const response = await HttpUtils.post(`${process.env.VUE_APP_API_BASE_URL}/api/order`, {
      data: orderData
    })

   const deleteCarResponse = await deleteCarItem(props.carId,orderData.goods)
    if (response.code === 200 && deleteCarResponse.code === 200 ) {
      ElMessage.success('订单创建成功')
      emit('success', response.data.order_id)
      CartUtils.clearCart()
      visible.value = false
    } else {
      ElMessage.error(response.message || '订单创建失败')
    }
  } catch (error) {
    console.error('订单提交失败:', error)
    ElMessage.error(error.message || '订单提交失败')
  } finally {
    submitting.value = false
  }
}
</script>

<style scoped>
.full-width {
  width: 100%;
}

.order-summary {
  margin: 20px 0;
  padding: 15px;
  background: #f8f9fa;
  border-radius: 8px;
}

.summary-item {
  display: flex;
  justify-content: space-between;
  margin: 10px 0;
  font-size: 14px;
  color: #606266;
}

.summary-item.total {
  padding-top: 10px;
  border-top: 1px solid #eee;
  font-size: 16px;
  color: #303133;
}

.summary-item.total .value {
  color: #ff5000;
  font-weight: 600;
}

.dialog-footer {
  margin-top: 20px;
  text-align: right;
}

/* 优化弹窗样式 */
.settle-dialog :deep(.el-dialog__header) {
  border-bottom: 1px solid #eee;
  padding: 20px;
}

.settle-dialog :deep(.el-dialog__body) {
  padding: 20px;
}

.settle-dialog :deep(.el-form-item__label) {
  font-weight: 500;
  color: #303133;
}
</style>