<!-- GoodsSort.vue -->
<template>
  <el-collapse v-model="activeNames" class="goods-sort" accordion>
    <el-collapse-item title="品类" name="category">
      <el-radio-group v-model="filterParams.category">
        <el-radio-button label="">全部</el-radio-button>
        <el-radio-button
            v-for="item in categories"
            :key="item.value"
            :label="item.value"
        >
          {{ item.label }}
        </el-radio-button>
      </el-radio-group>
    </el-collapse-item>

    <el-collapse-item title="排序" name="sort">
      <el-radio-group v-model="filterParams.sortType">
        <el-radio-button label="default">默认</el-radio-button>
        <el-radio-button label="sales">销量</el-radio-button>
        <el-radio-button label="price">价格</el-radio-button>
        <el-radio-button label="hot">人气</el-radio-button>
      </el-radio-group>
    </el-collapse-item>
  </el-collapse>
</template>

<script setup>
import { ref, reactive, watch,defineProps } from 'vue'
const props = defineProps({
  currentCategory: {
    type: String,
    default: ''
  }
})
const emit = defineEmits(['filter-change'])

const activeNames = ref(['category', 'sort'])
const filterParams = reactive({
  category: props.currentCategory,
  sortType: 'default'
})



const categories = [
  { label: '数码电子', value: '1' },
  { label: '服装服饰', value: '2' },
  { label: '家居生活', value: '3' },
  { label: '美妆护肤', value: '4' },
  { label: '图书音像', value: '5' },
  { label: '冷冻生鲜', value: '6' },
]
// 添加对父组件分类值的监听
watch(() => props.currentCategory, (newVal) => {
  filterParams.category = newVal
})

watch(filterParams, (newVal) => {
  console.log(filterParams.category)
  emit('filter-change', newVal)
}, { deep: true })
</script>

<style scoped>
.goods-sort {
  background: #fff;
  border-radius: 8px;
  box-shadow: 0 2px 12px rgba(0, 0, 0, 0.06);
  margin-bottom: 20px;
}

:deep(.el-collapse-item__header) {
  height: 50px;
  font-size: 16px;
  color: #303133;
  padding: 0 20px;
  border-bottom: 1px solid #f0f0f0;
}

:deep(.el-radio-button__orig-radio:checked + .el-radio-button__inner) {
  background: #ff5000;
  border-color: #ff5000;
  box-shadow: none;
}

:deep(.el-radio-button__inner) {
  border-radius: 16px !important;
  padding: 8px 20px;
  transition: all 0.3s ease;
}

:deep(.el-radio-button__inner:hover) {
  color: #ff5000;
}
</style>